const listWorkLogs = `-- name: ListWorkLogs :many
SELECT
    wl.id,
    wl.tenant_id,
    wl.engagement_id,
    e.title AS engagement_title,
    e.engagement_code,
    e.project_label,
    e.project_code,
    e.cost_center,
    wl.worker_profile_id,
    wp.display_name AS worker_display_name,
    wp.worker_code,
    wp.employee_id,
    e.reporting_manager_id,
    e.department_id,
    d.name AS department_name,
    e.branch_id,
    b.branch_name AS branch_name,
    wl.log_date,
    wl.hours_worked,
    wl.billable_hours,
    wl.work_summary,
    wl.deliverable_reference,
    wl.status,
    wl.submitted_at,
    wl.submitted_by,
    wl.reviewed_at,
    wl.reviewed_by,
    wl.review_comment,
    wl.metadata,
    wl.inactive,
    wl.created_at,
    wl.created_by,
    wl.updated_at,
    wl.updated_by
FROM hrms.work_logs wl
JOIN hrms.engagements e ON e.tenant_id = wl.tenant_id AND e.id = wl.engagement_id AND NOT e.inactive
JOIN hrms.worker_profiles wp ON wp.tenant_id = wl.tenant_id AND wp.id = wl.worker_profile_id AND NOT wp.inactive
LEFT JOIN hrms.departments d ON d.tenant_id = wl.tenant_id AND d.id = e.department_id AND NOT d.inactive
LEFT JOIN hrms.branches b ON b.tenant_id = wl.tenant_id AND b.id = e.branch_id AND NOT b.inactive
WHERE wl.tenant_id = $1
  AND ($2::uuid IS NULL OR wl.engagement_id = $2::uuid)
  AND ($3::uuid IS NULL OR wl.worker_profile_id = $3::uuid)
  AND ($4::text IS NULL OR wl.status = $4::text)
  AND ($5::date IS NULL OR wl.log_date >= $5::date)
  AND ($6::date IS NULL OR wl.log_date <= $6::date)
  AND (
      $7::text IS NULL
      OR wl.work_summary ILIKE '%' || $7::text || '%'
      OR wl.deliverable_reference ILIKE '%' || $7::text || '%'
      OR e.title ILIKE '%' || $7::text || '%'
      OR e.project_label ILIKE '%' || $7::text || '%'
      OR wp.display_name ILIKE '%' || $7::text || '%'
      OR wp.worker_code ILIKE '%' || $7::text || '%'
  )
  AND NOT wl.inactive
ORDER BY
    CASE wl.status WHEN 'submitted' THEN 0 WHEN 'draft' THEN 1 WHEN 'rejected' THEN 2 WHEN 'approved' THEN 3 ELSE 4 END,
    wl.log_date DESC,
    wl.updated_at DESC
`

